import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class XSSFixedServlet extends HttpServlet {

    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");
        String safeUserInput = escapeHtml(userInput); // Sanitize user input

        String responseMessage = "Hello, " + safeUserInput + "!";

        // Properly handling user input with sanitization
        PrintWriter out = response.getWriter();
        out.println("<html><body>");
        out.println("<h1>" + responseMessage + "</h1>");
        out.println("</body></html>");
    }

    private String escapeHtml(String input) {
        return input != null ? input.replace("&", "&amp;")
                                    .replace("<", "&lt;")
                                    .replace(">", "&gt;")
                                    .replace("\"", "&quot;")
                                    .replace("'", "&#39;") : "";
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
